BEGIN; CREATE OR REPLACE FUNCTION public.trig_fn_delivery_plan_awareness() RETURNS trigger LANGUAGE plpgsql SET search_path = public AS $$ BEGIN IF OLD.planned_qty IS DISTINCT FROM NEW.planned_qty THEN NEW.qty_updated_at := now(); NEW.prev_planned_qty := OLD.planned_qty; END IF; IF (OLD.planned_qty IS DISTINCT FROM NEW.planned_qty) OR (OLD.backlog_qty IS DISTINCT FROM NEW.backlog_qty) OR (OLD.actual_qty IS DISTINCT FROM NEW.actual_qty) THEN NEW.is_completed := ( (COALESCE(NEW.planned_qty, 0) + COALESCE(NEW.backlog_qty, 0)) > 0 AND COALESCE(NEW.actual_qty, 0) >= (COALESCE(NEW.planned_qty, 0) + COALESCE(NEW.backlog_qty, 0)) ); END IF; RETURN NEW; END; $$; UPDATE public.delivery_plans SET is_completed = false, updated_at = now() WHERE deleted_at IS NULL AND COALESCE(planned_qty, 0) = 0 AND COALESCE(backlog_qty, 0) = 0 AND COALESCE(actual_qty, 0) = 0 AND is_completed = true; NOTIFY pgrst, 'reload schema'; COMMIT;